styles:
:root {
  --blue:      #3A7BFE;
  --blue-dark: #1A5CE0;
  --blue-deep: #0D3FA6;
  --blue-light:#EBF2FF;
  --blue-mid:  #C2D9FF;
  --orange:    #FF6B35;
  --green:     #22C55E;
  --red:       #EF4444;
  --yellow:    #F59E0B;
  --text:      #1A1A2E;
  --text-2:    #4B5575;
  --text-3:    #8892B0;
  --bg:        #F6F9FF;
  --white:     #FFFFFF;
  --border:    #DDE5FF;
  --shadow:    0 4px 24px rgba(58,123,254,0.10);
  --shadow-lg: 0 8px 40px rgba(58,123,254,0.16);
  --radius:    16px;
  --radius-sm: 10px;
}
* { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }
body {
  font-family: 'Noto Sans KR', sans-serif;
  background: var(--bg);
  color: var(--text);
  line-height: 1.7;
  font-size: 16px;
}

/* ── 상단 네비게이션 ── */
.nav {
  position: sticky; top: 0; z-index: 100;
  background: rgba(255,255,255,0.92);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
  padding: 0 24px;
}
.nav-inner {
  max-width: 960px; margin: 0 auto;
  display: flex; align-items: center; justify-content: space-between;
  height: 60px;
}
.nav-logo {
  display: flex; align-items: center; gap: 10px;
  font-weight: 700; font-size: 17px; color: var(--blue);
  text-decoration: none;
}
.nav-logo .logo-icon {
  width: 34px; height: 34px; background: var(--blue);
  border-radius: 10px;
  display: flex; align-items: center; justify-content: center;
}
.nav-logo .logo-icon svg { width: 20px; height: 20px; fill: white; }
.nav-links {
  display: flex; gap: 6px;
  list-style: none;
}
.nav-links a {
  text-decoration: none; color: var(--text-2);
  font-size: 14px; font-weight: 500;
  padding: 6px 12px; border-radius: 8px;
  transition: all .2s;
}
.nav-links a:hover { background: var(--blue-light); color: var(--blue); }
.hamburger {
  display: none; flex-direction: column; gap: 5px;
  background: none; border: none; cursor: pointer; padding: 4px;
}
.hamburger span { width: 24px; height: 2px; background: var(--text-2); border-radius: 2px; transition: .3s; }

/* ── 히어로 ── */
.hero {
  background: linear-gradient(135deg, #1A3A6B 0%, var(--blue) 50%, #5B9FFF 100%);
  padding: 80px 24px 100px;
  text-align: center; position: relative; overflow: hidden;
}
.hero::before {
  content: '';
  position: absolute; inset: 0;
  background: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Ccircle cx='30' cy='30' r='1.5' fill='rgba(255,255,255,0.08)'/%3E%3C/svg%3E") repeat;
}
.hero-badge {
  display: inline-block; background: rgba(255,255,255,0.18);
  color: white; font-size: 13px; font-weight: 600;
  padding: 6px 16px; border-radius: 100px;
  border: 1px solid rgba(255,255,255,0.3);
  margin-bottom: 24px; position: relative;
}
.hero h1 {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(30px, 5vw, 52px);
  font-weight: 700; color: white;
  line-height: 1.3; margin-bottom: 20px;
  position: relative;
}
.hero h1 span { color: #FFD166; }
.hero p {
  font-size: clamp(15px, 2.5vw, 18px);
  color: rgba(255,255,255,0.88);
  max-width: 560px; margin: 0 auto 36px;
  position: relative;
}
.hero-cta {
  display: inline-flex; align-items: center; gap: 8px;
  background: white; color: var(--blue);
  font-weight: 700; font-size: 16px;
  padding: 14px 28px; border-radius: 100px;
  text-decoration: none;
  box-shadow: 0 8px 32px rgba(0,0,0,0.2);
  transition: transform .2s, box-shadow .2s;
  position: relative;
}
.hero-cta:hover { transform: translateY(-2px); box-shadow: 0 12px 40px rgba(0,0,0,0.28); }
.hero-cta svg { width: 18px; height: 18px; }
.hero-stats {
  display: flex; justify-content: center; gap: 40px;
  margin-top: 56px; position: relative;
}
.hero-stat { text-align: center; }
.hero-stat strong { display: block; font-size: 26px; font-weight: 900; color: white; }
.hero-stat span { font-size: 13px; color: rgba(255,255,255,0.7); }

/* ── 공통 레이아웃 ── */
.section { padding: 72px 24px; }
.section-inner { max-width: 960px; margin: 0 auto; }
.section-title {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(22px, 3.5vw, 30px);
  font-weight: 700; margin-bottom: 8px; color: var(--text);
}
.section-sub {
  color: var(--text-2); font-size: 15px; margin-bottom: 40px;
}
.section-num {
  display: inline-flex; align-items: center; gap: 10px;
  margin-bottom: 16px;
}
.section-num .num {
  width: 36px; height: 36px; background: var(--blue);
  border-radius: 50%; display: flex; align-items: center; justify-content: center;
  color: white; font-weight: 700; font-size: 16px; flex-shrink: 0;
}
.section-num .label {
  font-size: 13px; font-weight: 600; color: var(--blue);
  text-transform: uppercase; letter-spacing: .06em;
}

/* ── 목차 ── */
.toc-section { background: white; padding: 48px 24px; }
.toc-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 12px;
}
.toc-card {
  display: flex; align-items: center; gap: 12px;
  padding: 14px 16px;
  background: var(--blue-light); border-radius: var(--radius-sm);
  text-decoration: none; color: var(--text);
  transition: all .2s; border: 2px solid transparent;
}
.toc-card:hover { border-color: var(--blue); background: white; transform: translateY(-2px); box-shadow: var(--shadow); }
.toc-card .toc-icon {
  width: 36px; height: 36px; background: var(--blue);
  border-radius: 8px; display: flex; align-items: center; justify-content: center;
  color: white; font-size: 18px; flex-shrink: 0;
}
.toc-card .toc-text { font-size: 14px; font-weight: 600; }
.toc-card .toc-step { font-size: 11px; color: var(--text-3); }

/* ── 클로드 코드란? ── */
.what-section { background: white; }
.what-grid {
  display: grid; grid-template-columns: 1fr 1fr;
  gap: 32px; align-items: center;
}
.what-visual {
  background: linear-gradient(135deg, var(--blue-deep), var(--blue));
  border-radius: 20px; padding: 32px;
  font-family: 'Courier New', monospace;
  color: rgba(255,255,255,0.9); font-size: 13px;
  line-height: 1.8; position: relative; overflow: hidden;
}
.what-visual::before {
  content: ''; position: absolute;
  top: -40px; right: -40px;
  width: 120px; height: 120px;
  background: rgba(255,255,255,0.06);
  border-radius: 50%;
}
.what-visual .term-bar {
  display: flex; gap: 6px; margin-bottom: 20px;
}
.term-dot { width: 12px; height: 12px; border-radius: 50%; }
.term-dot.red { background: #FF5F57; }
.term-dot.yellow { background: #FFBD2E; }
.term-dot.green { background: #28CA41; }
.what-visual .prompt { color: #7DD3FC; }
.what-visual .cmd { color: white; }
.what-visual .res { color: #A5F3B0; font-size: 12px; }
.what-visual .typing-cursor {
  display: inline-block; width: 8px; height: 14px;
  background: white; animation: blink 1s step-end infinite; vertical-align: middle;
}
@keyframes blink { 50% { opacity: 0; } }
.feature-list { list-style: none; }
.feature-list li {
  display: flex; align-items: flex-start; gap: 12px;
  padding: 12px 0; border-bottom: 1px solid var(--border);
}
.feature-list li:last-child { border-bottom: none; }
.feature-icon {
  width: 32px; height: 32px; border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  font-size: 16px; flex-shrink: 0;
}
.feature-text strong { display: block; font-size: 15px; color: var(--text); }
.feature-text span { font-size: 13px; color: var(--text-2); }

/* ── 준비물 ── */
.prereq-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(260px, 1fr));
  gap: 20px;
}
.prereq-card {
  background: white; border-radius: var(--radius);
  padding: 28px 24px; border: 2px solid var(--border);
  transition: border-color .2s, box-shadow .2s;
}
.prereq-card:hover { border-color: var(--blue-mid); box-shadow: var(--shadow); }
.prereq-card .card-icon {
  width: 52px; height: 52px; border-radius: 14px;
  display: flex; align-items: center; justify-content: center;
  font-size: 26px; margin-bottom: 16px;
}
.prereq-card h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.prereq-card p { font-size: 14px; color: var(--text-2); margin-bottom: 12px; }
.tag {
  display: inline-block; padding: 4px 10px;
  border-radius: 100px; font-size: 12px; font-weight: 600;
}
.tag-required { background: #FEE2E2; color: #DC2626; }
.tag-optional { background: #FEF9C3; color: #92400E; }
.tag-free { background: #D1FAE5; color: #065F46; }

/* ── OS 탭 ── */
.os-tabs {
  display: flex; gap: 8px; margin-bottom: 32px;
  flex-wrap: wrap;
}
.os-tab {
  display: flex; align-items: center; gap: 8px;
  padding: 10px 20px; border-radius: 100px;
  border: 2px solid var(--border);
  background: white; cursor: pointer;
  font-family: 'Noto Sans KR', sans-serif;
  font-size: 15px; font-weight: 600; color: var(--text-2);
  transition: all .2s;
}
.os-tab:hover { border-color: var(--blue-mid); color: var(--blue); }
.os-tab.active {
  background: var(--blue); border-color: var(--blue);
  color: white;
}
.os-tab svg { width: 20px; height: 20px; }
.os-content { display: none; }
.os-content.active { display: block; }

/* ── 스텝 카드 ── */
.step-list { display: flex; flex-direction: column; gap: 24px; }
.step-card {
  background: white; border-radius: var(--radius);
  border: 2px solid var(--border);
  overflow: hidden; transition: box-shadow .2s;
}
.step-card:hover { box-shadow: var(--shadow); }
.step-header {
  display: flex; align-items: center; gap: 16px;
  padding: 20px 24px; border-bottom: 1px solid var(--border);
  background: var(--blue-light);
}
.step-badge {
  width: 40px; height: 40px; background: var(--blue);
  border-radius: 50%; display: flex; align-items: center; justify-content: center;
  color: white; font-weight: 700; font-size: 17px; flex-shrink: 0;
}
.step-title { font-size: 17px; font-weight: 700; color: var(--text); }
.step-desc { font-size: 13px; color: var(--text-2); margin-top: 2px; }
.step-body { padding: 24px; }
.step-body p { font-size: 15px; color: var(--text-2); margin-bottom: 16px; line-height: 1.8; }
.step-body p:last-child { margin-bottom: 0; }

/* ── 명령어 블록 ── */
.cmd-block {
  background: #1A1A2E; border-radius: var(--radius-sm);
  padding: 16px 20px; margin: 16px 0;
  display: flex; align-items: flex-start; justify-content: space-between;
  gap: 12px;
}
.cmd-block code {
  font-family: 'Courier New', monospace;
  color: #A5F3B0; font-size: 14px; line-height: 1.6;
  word-break: break-all;
}
.cmd-block code .dollar { color: #7DD3FC; margin-right: 8px; }
.copy-btn {
  background: rgba(255,255,255,0.1); border: 1px solid rgba(255,255,255,0.2);
  color: rgba(255,255,255,0.7); border-radius: 6px;
  padding: 4px 10px; font-size: 12px; cursor: pointer;
  white-space: nowrap; transition: .2s;
  font-family: 'Noto Sans KR', sans-serif;
}
.copy-btn:hover { background: rgba(255,255,255,0.2); color: white; }
.copy-btn.copied { background: #22C55E; color: white; border-color: #22C55E; }

/* ── 팁 / 경고 박스 ── */
.info-box {
  border-radius: var(--radius-sm); padding: 16px 20px; margin: 16px 0;
  display: flex; gap: 12px; align-items: flex-start;
}
.info-box .box-icon { font-size: 20px; flex-shrink: 0; margin-top: 2px; }
.info-box .box-text { font-size: 14px; line-height: 1.7; }
.info-box .box-text strong { display: block; font-size: 14px; margin-bottom: 4px; }
.info-tip { background: #EFF6FF; border-left: 4px solid var(--blue); }
.info-warn { background: #FFFBEB; border-left: 4px solid var(--yellow); }
.info-success { background: #F0FDF4; border-left: 4px solid var(--green); }
.info-danger { background: #FEF2F2; border-left: 4px solid var(--red); }

/* ── 인증 섹션 ── */
.auth-flow {
  display: flex; gap: 0; flex-wrap: wrap;
  background: white; border-radius: var(--radius);
  border: 2px solid var(--border); overflow: hidden;
}
.auth-step {
  flex: 1; min-width: 180px; padding: 24px 20px;
  border-right: 1px solid var(--border); position: relative;
  text-align: center;
}
.auth-step:last-child { border-right: none; }
.auth-step::after {
  content: '→';
  position: absolute; right: -12px; top: 50%;
  transform: translateY(-50%);
  color: var(--blue); font-size: 20px; font-weight: 700;
  background: white; padding: 4px;
  z-index: 1;
}
.auth-step:last-child::after { display: none; }
.auth-num {
  width: 36px; height: 36px; background: var(--blue-light);
  border-radius: 50%; display: flex; align-items: center; justify-content: center;
  color: var(--blue); font-weight: 700; font-size: 16px;
  margin: 0 auto 10px;
}
.auth-step h4 { font-size: 14px; font-weight: 700; margin-bottom: 4px; }
.auth-step p { font-size: 12px; color: var(--text-2); }

/* ── 문제 해결 ── */
.trouble-section { background: white; }
.trouble-list { display: flex; flex-direction: column; gap: 12px; }
.trouble-item {
  border: 2px solid var(--border); border-radius: var(--radius-sm);
  overflow: hidden;
}
.trouble-q {
  display: flex; align-items: center; justify-content: space-between; gap: 12px;
  padding: 16px 20px; cursor: pointer;
  background: white; transition: background .2s;
  border: none; width: 100%;
  font-family: 'Noto Sans KR', sans-serif;
  font-size: 15px; font-weight: 600; color: var(--text);
  text-align: left;
}
.trouble-q:hover { background: var(--blue-light); }
.trouble-q .q-icon {
  width: 28px; height: 28px; border-radius: 50%;
  background: #FEE2E2; color: #DC2626;
  display: flex; align-items: center; justify-content: center;
  font-size: 13px; font-weight: 700; flex-shrink: 0;
}
.trouble-q .q-text { flex: 1; }
.trouble-q .q-arrow { color: var(--text-3); font-size: 12px; transition: transform .2s; }
.trouble-item.open .q-arrow { transform: rotate(180deg); }
.trouble-item.open { border-color: var(--blue-mid); }
.trouble-a {
  padding: 0 20px; max-height: 0; overflow: hidden;
  transition: max-height .3s ease, padding .3s ease;
}
.trouble-item.open .trouble-a {
  padding: 0 20px 20px; max-height: 500px;
}
.trouble-a p { font-size: 14px; color: var(--text-2); line-height: 1.8; }

/* ── FAQ ── */
.faq-grid {
  display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
  gap: 20px;
}
.faq-card {
  background: white; border-radius: var(--radius);
  padding: 24px; border: 2px solid var(--border);
}
.faq-card .q {
  font-size: 15px; font-weight: 700; color: var(--blue);
  margin-bottom: 10px; display: flex; gap: 8px; align-items: flex-start;
}
.faq-card .q::before {
  content: 'Q'; width: 24px; height: 24px;
  background: var(--blue); color: white; border-radius: 6px;
  display: flex; align-items: center; justify-content: center;
  font-size: 12px; font-weight: 700; flex-shrink: 0; margin-top: 1px;
}
.faq-card .a { font-size: 14px; color: var(--text-2); line-height: 1.7; padding-left: 32px; }

/* ── 완료 배너 ── */
.done-section {
  background: linear-gradient(135deg, var(--blue-deep) 0%, var(--blue) 100%);
  padding: 80px 24px; text-align: center;
}
.done-section h2 {
  font-family: 'Noto Serif KR', serif;
  font-size: clamp(24px, 4vw, 36px);
  color: white; margin-bottom: 16px;
}
.done-section p { color: rgba(255,255,255,0.85); font-size: 16px; margin-bottom: 36px; }
.done-commands {
  display: flex; justify-content: center; gap: 16px; flex-wrap: wrap;
  margin-bottom: 40px;
}
.done-cmd {
  background: rgba(255,255,255,0.12); border: 1px solid rgba(255,255,255,0.25);
  border-radius: var(--radius-sm); padding: 12px 20px;
  font-family: 'Courier New', monospace;
  color: #A5F3B0; font-size: 14px;
}
.done-link {
  display: inline-block;
  background: white; color: var(--blue);
  font-weight: 700; font-size: 15px;
  padding: 14px 32px; border-radius: 100px;
  text-decoration: none;
  transition: transform .2s, box-shadow .2s;
  box-shadow: 0 4px 20px rgba(0,0,0,0.2);
}
.done-link:hover { transform: translateY(-2px); box-shadow: 0 8px 32px rgba(0,0,0,0.3); }

/* ── 푸터 ── */
footer {
  background: #1A1A2E; color: rgba(255,255,255,0.5);
  padding: 32px 24px; text-align: center; font-size: 13px;
}
footer a { color: rgba(255,255,255,0.7); }

/* ── 진행바 ── */
.progress-bar {
  position: fixed; top: 60px; left: 0; right: 0; height: 3px;
  background: rgba(58,123,254,0.15); z-index: 99;
}
.progress-fill {
  height: 100%; background: var(--blue);
  transition: width .1s; width: 0%;
}

/* ── 맨 위로 버튼 ── */
.back-top {
  position: fixed; bottom: 28px; right: 24px;
  width: 48px; height: 48px; border-radius: 50%;
  background: var(--blue); color: white;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer; border: none;
  box-shadow: 0 4px 16px rgba(58,123,254,0.4);
  transition: transform .2s, opacity .3s;
  opacity: 0; pointer-events: none; font-size: 20px;
  font-family: sans-serif;
}
.back-top.visible { opacity: 1; pointer-events: auto; }
.back-top:hover { transform: translateY(-3px); }

/* ── 반응형 ── */
@media (max-width: 768px) {
  .nav-links { display: none; }
  .nav-links.open {
    display: flex; flex-direction: column;
    position: fixed; top: 60px; left: 0; right: 0;
    background: white; padding: 16px 24px;
    border-bottom: 1px solid var(--border);
    box-shadow: var(--shadow); z-index: 99;
  }
  .hamburger { display: flex; }
  .hero-stats { gap: 20px; }
  .what-grid { grid-template-columns: 1fr; }
  .what-visual { order: -1; }
  .auth-flow { flex-direction: column; }
  .auth-step { border-right: none; border-bottom: 1px solid var(--border); }
  .auth-step::after { content: '↓'; right: 50%; bottom: -14px; top: auto; transform: translateX(50%); }
  .auth-step:last-child::after { display: none; }
  .section { padding: 48px 20px; }
}
@media (max-width: 480px) {
  .hero { padding: 60px 20px 80px; }
  .hero-stats { flex-direction: column; gap: 16px; }
  .step-header { padding: 16px; }
  .step-body { padding: 16px; }
}
